code = """import json
import re

# Load citations
citations_path = locals()['var_function-call-8331430492114871094']
with open(citations_path, 'r') as f:
    citations = json.load(f)

# Create a dictionary for quick lookup: title -> citation_count
citation_map = {c['title']: c['citation_count'] for c in citations}

# Load paper texts
papers_path = locals()['var_function-call-17050301767549123802']
with open(papers_path, 'r') as f:
    papers = json.load(f)

acm_citations = []

for paper in papers:
    text = paper.get('text', '')
    filename = paper.get('filename', '')
    title = filename.replace('.txt', '')
    
    # Check if ACM paper
    # "ACM" usually appears in copyright notice or header/footer.
    # Given the prompt, checking for "ACM" string is likely sufficient.
    # But let's be slightly more robust if possible.
    # The sample text had "ACM Classification Keywords", "Copyright 2015 © ACM", "Request permissions from permissions@acm.org".
    if "ACM" in text:
        if title in citation_map:
            count = citation_map[title]
            acm_citations.append(float(count))

if not acm_citations:
    result = 0
else:
    result = sum(acm_citations) / len(acm_citations)

print(f"Found {len(acm_citations)} ACM papers.")
print(f"Average citation count: {result}")
print("__RESULT__:")
print(result)"""

